
import { ref, onMounted, reactive } from "vue";
import { ResultList } from "./types/index";
import api from "./service/api";
import headers from "./components/header.vue";
import SectionTitle from "./components/sectionTitle.vue";
import SectionNum from "./components/sectionNum.vue";
import SectionState from "./components/sectionState.vue";
import SectionText from "./components/sectionText.vue";
import sensors from "../../utils/sensors";
import queryString from "query-string";
// import { planInfo } from './mock';
export default {
  name: "planDetail",
  components: {
    headers,
    SectionTitle,
    SectionNum,
    SectionState,
    SectionText,
  },
  setup() {
    const sectionHeaderInfo = reactive({
      show_module_type: "",
      title: "",
      subtitle: "",
      schedule_cycle: 0,
      schedule_pass_cycle: 0,
      schedule_process: 0,
    });
    const hadDel = ref(false);
    const knowledge = ref({
      knowledge_name: 0,
      learn_duration: 0,
      answers_numbers: 0,
      revision_numbers: 0,
    });
    const knowledgeList = ref([] as any);
    // const handleSensor = (info:ResultList)=>{
    //   // source=1（代表首页）2 代表日历
    //   const source = getUrlParam('source') || ''
    //   const plan_task_completion = parseFloat(info.accuracy_rate)
    //   const plan_task_deadline = info.schedule_pass_cycle
    //   const plan_name = info.subtitle
    //   const plan_task_name = info.title
    //   const plan_details_source = source==='1'?'首页':(source==='2'?'日历':'')
    //   sensors.track('plan_task_details', {
    //     plan_task_completion: plan_task_completion,
    //     plan_task_deadline:plan_task_deadline,
    //     plan_name:plan_name,
    //     plan_task_name:plan_task_name,
    //     plan_details_source:plan_details_source
    //   })
    // }
    const handleData = (info: ResultList) => {
      sectionHeaderInfo.title = info.title;
      sectionHeaderInfo.subtitle = info.subtitle;
      sectionHeaderInfo.schedule_cycle = info.schedule_cycle;
      sectionHeaderInfo.schedule_pass_cycle = info.schedule_pass_cycle;
      sectionHeaderInfo.show_module_type = info.show_module_type;
      sectionHeaderInfo.schedule_process = info.schedule_process;
      knowledgeList.value = info.knowledge;
    };
    const getList = () => {
      const { schedule_id = "", child_tal_id = "" } = queryString.parse(
        location.hash.split("?")[1] || ""
      );

      api
        .getPlanSchedule({
          schedule_id: schedule_id,
          child_tal_id: child_tal_id,
        })
        .then((res: ResultList) => {
          if (res.data.errcode === 0 && res.data.data) {
            const info = res.data.data;
            console.log(info);
            handleData(info);
            // handleSensor(info)
            // 计划被取消，导致任务被删除
          } else if(res.data.errcode === 24204) {
            hadDel.value = true;
          } 
        });
      // handleData(planInfo)
      // handleSensor(planInfo)
    };
    onMounted(() => {
      getList();
    });
    return {
      sectionHeaderInfo,
      knowledge,
      headers,
      knowledgeList,
      hadDel,
    };
  },
};
