
import { ref, onMounted, reactive } from 'vue';
import { useRoute } from 'vue-router';
import { ResultList } from './types/index';
import { getUrlParam, getUrlParamNew, getLearningMachineVersion } from '@/utils/index';
import api from './service/api';
import headers from './components/header.vue';
import SectionTitle from './components/sectionTitle.vue';
import SectionNum from './components/sectionNum.vue';
import SectionState from './components/sectionState.vue';
import SectionText from './components/sectionText.vue';
import SectionProgress from './components/sectionProgress.vue';
import sensors from '../../utils/sensors';
export default {
  name: 'studyDetail',
  components: {
    headers,
    SectionTitle,
    SectionNum,
    SectionState,
    SectionText,
    SectionProgress
  },
  setup() {
    const list = ref([] as any);
    const maxDuration = ref(0);
    const sectionHeaderInfo = reactive({
      show_module_type: '',
      title: '',
      subject_name: '',
      wrong_question: ''
    });

    const source = ref('jzx');

    const handleData = (info: ResultList) => {
      sectionHeaderInfo.title = info.title;
      sectionHeaderInfo.subject_name = info.subject_name;
      sectionHeaderInfo.show_module_type = info.show_module_type;
      sectionHeaderInfo.wrong_question = info.wrong_question;
      list.value = normalizeList(info.knowledge, source.value);
      getMaxDuration(list.value);
    };

    const normalizeList = (knowledges: any, source: string) => {
      if (source.indexOf('jzx1.5') > -1) {
        // 精准学1.5 需要处理显示方式

        // eslint-disable-next-line no-inner-declarations
        function validateKnowledge(knowledge: any) {
          let depth = 0;
          let fastKnowledge = knowledge;
          let slowKnowledge = knowledge;
          const cacheKnowledge = JSON.parse(JSON.stringify(knowledge));
          while (fastKnowledge !== null) {
            depth++;
            slowKnowledge = fastKnowledge;
            fastKnowledge =
              fastKnowledge.knowledge?.length > 0
                ? fastKnowledge.knowledge[0]
                : null;
          }

          console.log('depth--->', depth);

          if (depth === 2) {
            // 叶子层级有知识点掌握度
            if (slowKnowledge.knowledge_mastery) {
              // 构建一个节点 占用位置和错题数目
              cacheKnowledge.knowledge = [{
                knowledge: cacheKnowledge.knowledge,
                wrong_numbers: cacheKnowledge.wrong_numbers,
                answers_numbers: cacheKnowledge.answers_numbers,
                revision_numbers: cacheKnowledge.revision_numbers,
                accuracy_rate: cacheKnowledge.accuracy_rate,
                learn_duration: cacheKnowledge.learn_duration
              }]

              return cacheKnowledge;
            } else {
              // 无知识点掌握度
              return cacheKnowledge;
            }
          } else if (depth === 1) {
            cacheKnowledge.knowledge = [knowledge];
            return cacheKnowledge;
          } else {
            return cacheKnowledge;
          }
        }

        return knowledges.map((knowledge: any) => validateKnowledge(knowledge));
      } else {
        return knowledges;
      }
    };

    const handleSensor = (info: ResultList) => {
      const situation_name = info.title;
      sensors.track('situationdetails_details', {
        situation_name: situation_name
      });
    };
    const getMaxDuration = (list: Array<any>) => {
      // 启蒙课模板
      if (sectionHeaderInfo.show_module_type === 'F') {
        list.map((item) => {
          if (item.learn_duration && item.learn_duration > maxDuration.value)
            maxDuration.value = item.learn_duration;
        });
        // 非启蒙课模板
      } else {
        list.map((item1: any) => {
          item1.knowledge.map((item2: any) => {
            if (
              item2.learn_duration &&
              item2.learn_duration > maxDuration.value
            )
              maxDuration.value = item2.learn_duration;
          });
        });
      }
    };
    const getList = async () => {
      const tal_id = getUrlParam('tal_id') || '';
      const date = getUrlParam('date') || '';
      source.value = getUrlParam('source') || '';


      console.log('label', decodeURIComponent(getUrlParamNew('label') || ''))

      api
        .getStudySchedule({
          tal_id: tal_id,
          source: source.value,
          date: date,
          label: decodeURIComponent(getUrlParamNew('label') || ''),
          xpad_type: getUrlParamNew('xpad_type') || ''
        })
        .then((res: ResultList) => {
          if (res.data.errcode === 0 && res.data.data) {
            const info = res.data.data;
            console.log(info);
            handleData(info);
            handleSensor(info);
          }
        });

      // setTimeout(() => {
      //   // mockjs1: 听一听 mockjs2: 启蒙 mockjs3: 励步
      //   const route = useRoute()
      //   console.log(route.query.moduetype)
      //   let str = Number(route?.query?.moduetype || 0 )
      //   const mockjsList = [mockjs1, mockjs2, mockjs3, mockjs4, mockjs5, mockjs6, mockjs7, mockjs8]
      //   handleData(mockjsList[str])
      //   handleSensor(mockjsList[str])
      //   handleData(mockjs8)
      //   handleSensor(mockjs8)
      // }, 500)
    };
    onMounted(() => {
      // const route = useRoute()
      // let str = Number(route?.query?.moduetype || 0)
      // console.log(route, route.query, route.query.moduetype)
      // const mockjsList = [mockjs1, mockjs2, mockjs3, mockjs4, mockjs5, mockjs6, mockjs7, mockjs8]
      // handleData(mockjsList[str])
      // handleSensor(mockjsList[str])
      getList();
    });
    return {
      sectionHeaderInfo,
      list,
      headers,
      maxDuration,
      source
    };
  }
};
