export const timeFormat = (time: number, type = "YMD") => {
  const date = new Date(time);
  const year = date.getFullYear();
  const month = date.getMonth() + 1;
  const day = date.getDate();
  const dayOfWeek = date.getDay();

  switch (type) {
    case "YMD":
      return `${year}年${month}月${day}日`;
    case "YM":
      return `${year}年${month}月`;
    case "MD":
      return `${month}月${day}日`;
    case "MDW":
      return `${month}月${day}日 周${dayOfWeek}`;
    default:
      return "";
      break;
  }
};

export const subjectColorMap: any = {
  数学: "#FDF07A",
  语文: "#F5BCBA",
  英语: "#C9B5FA",
  物理: "#99C6FA",
  化学: "#BAF36E",
  生物: "#D9F460",
  地理: "#F19B53",
  历史: "#F5BC72",
  道德与法治: "#9E7AF7",
  其他: "#FF98B2",
};

export const getSubjectColor = (subject: string) => {
  return subjectColorMap[subject] || "#FF98B2";
};
export const getLabelName = (detail: any) => {
  if (detail.scene_type === 6) {
    return "小计划";
  } else if (detail.group_type === 6) {
    return "自定义";
  } else if (detail.rule_obj?.content_source === 19) {
    return "家长任务";
  } else if (detail.rule_obj?.content_source === 20) {
    return "作业模式";
  } else if (detail.group_type === 14) {
    return "智能定制";
  } else {
    return "官方计划";
  }
};
