import ApiService, { ResponseType } from '@/api/api';
import { getUserInfo } from '@/views/CustomTaskList/api';

export default {
  async getPlanSchedule(obj: any): ResponseType<string> {
    const {token} = await getUserInfo();


    return ApiService.post('/parent/api/v1/study-schedule/info', {
      ...obj,
      token
    });
  },
  async getStudySchedule(obj: any): ResponseType<string> {
    const {token} = await getUserInfo();
    return ApiService.post('/data/parent/report/detail', {
      ...obj,
      token
    });
  }
};
