
import { ref } from 'vue';
import { formatSeconds } from '@/utils/index';
export default {
  name: 'sectionTitle',
  props: ["info"],
  components: {
  },
  setup () {
    const stateText = (state:number)=>{
      const obj = {
        0:'未开始',
        1:'进行中',
        2:'完成'
      } as any
      return obj[state]
    }
    const handleDuration = (time:number)=>{
      if(time){
        return formatSeconds(time)
      }else{
        return '0秒'
      }
    }
    return {
      stateText,
      handleDuration
    }
  }
}
