
import { ref } from 'vue';
import { formatSeconds } from '@/utils/index';
export default {
  name: 'sectionProgress',
  props: ["knowledge", "maxDuration"],
  components: {
  },
  setup (props: any) {
    const handleDuration = (time:number)=>{
      if(time){
        return formatSeconds(time)
      }else{
        return 0
      }
    }
    const handelKnowledge = (knowledge:any)=>{
      // let maxDuration = 0;
      // knowledge.map((item:any)=>{
      //   if(item.learn_duration>maxDuration) maxDuration = item.learn_duration
      // })
      return knowledge.map((item:any)=>{
        const max = 160;
        item.duration_len = parseInt(item.learn_duration/props.maxDuration*max/document.body.clientWidth*100 as any) +'vw'
        return item
      })
    }
    return {
      handleDuration,
      handelKnowledge
    }
  }
}
