import ApiService from '@/api/api';
import { getUserInfo } from '../CustomTaskList/api';

export const getPlanDetail = async (params: {
  tal_id: string;
  group_id: string;
  group_type: number;
}) => {
  const { token } = await getUserInfo();

  return ApiService.post("/parent/api/v1/study-schedule/detail", {
    ...params,
    token,
  });
};
//取消计划
export const delPlan = async (data: any) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/stu-parent/schedule/v1/group/cancel", {
    ...data,
    stu_tal_id: stu_talid,
    token,
  });
};