
import { ref, onMounted, computed, onBeforeUnmount } from "vue";
import { Progress } from "vant";
import { compareVersion } from "@/utils/index";
import sensors from "@/utils/sensors";
import { isEdstars } from "@/utils/url";
import queryString from "query-string";

const labelStyle = {
  语文: "red1",
  语文启蒙: "red1",
  综合: "red2",
  道德与法制: "red2",
  数学: "yellow",
  历史: "yellow",
  思维训练: "yellow",
  英语: "purple",
  英语启蒙: "purple",
  物理: "blue",
  科学: "blue",
  化学: "green",
  生物: "green",
  工具: "blue2",
  地理: "blue2",
};
const __default__ = {
  name: "planHeader",
  props: ["title", "type", "info", "hadDel"],
  components: {
    ["Progress"]: Progress,
  },
  setup() {
    const isShowMore = ref(false);
    const { isFromH5 = "", tal_id = "" } = queryString.parse(
      location.hash.split("?")[1] || ""
    );
    const handlepercent = (info: any) => {
      if (info.schedule_process) {
        return Math.floor(info.schedule_process);
      } else {
        return 0;
      }
    };
    const goback = () => {
      if (isFromH5 === "1") {
        window.history.go(-1);
      } else {
        window.ConnectWebViewBridgeSDK.goback();
      }
    };
    const queryError = (info: any) => {
      if (info.wrong_number) {
        const domain = location.origin;
        const url =
          domain +
          "/mbxpp/#/parentBookError?plan_ids=" +
          info.plan_ids +
          "&tal_id=" +
          tal_id +
          "&source=" +
          2 +
          "&date=" +
          info.date +
          "&statusBarBgColor=FFFFFF" +
          "&appbar=hide";
        console.log(url);
        window.ConnectWebViewBridgeSDK.jumpToH5Handler({
          url: url,
          title: "错题",
        });
        sensors.track("wrong_question_list", {
          source_name: "学情详情",
          subject_name: "",
          wrong_num: info.wrong_number,
        });
      }
    };
    const getVersion = () => {
      window.ConnectWebViewBridgeSDK.getAppInfo((appInfo: any) => {
        console.log(appInfo?.version, "version");
        // 当前版本大于等于1.10.0
        if (
          appInfo?.version &&
          compareVersion("1.10.0", appInfo.version) <= 0
        ) {
          isShowMore.value = true;
        }
      });
    };

    const backBgOpacity = ref(0);
    const headerBgOpacity = computed(
      () => `rgba(255, 255, 255, ${backBgOpacity.value})`
    );

    const handleScroll = () => {
      let scrollTop =
        window.pageYOffset ||
        document.documentElement.scrollTop ||
        document.body.scrollTop; // 滚动条偏移量

      if (scrollTop > 30) scrollTop = 30;
      backBgOpacity.value = scrollTop / 30;
    };

    onMounted(() => {
      getVersion();

      handleScroll();
      window.addEventListener("scroll", handleScroll);
    });

    onBeforeUnmount(() => {
      window.removeEventListener("scroll", handleScroll);
    });
    return {
      handlepercent,
      goback,
      queryError,
      labelStyle,
      isShowMore,
      headerBgOpacity,
    };
  },
};

